import React from 'react';
import { ToastContainer, toast } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';

export const ToastWrapper = () => {
  return <ToastContainer position="top-right" autoClose={3000} hideProgressBar={false} />;
};

// Funções auxiliares para usar em qualquer componente
export const showSuccess = (message) => toast.success(message);
export const showError = (message) => toast.error(message);
export const showInfo = (message) => toast.info(message);
export const showWarning = (message) => toast.warning(message);
